<?php require_once __DIR__.'/includes/functions.php';if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();$email=$_POST['email'];$s=db()->prepare("SELECT id FROM users WHERE email=? AND status='Active'");$s->execute([$email]);$u=$s->fetch();if($u){$token=bin2hex(random_bytes(32));db()->prepare("INSERT INTO password_resets(user_id,token,expires_at) VALUES(?,?,DATE_ADD(NOW(),INTERVAL 1 HOUR))")->execute([$u['id'],$token]);$link=(isset($_SERVER['HTTPS'])?'https':'http').'://'.$_SERVER['HTTP_HOST'].BASE_URL.'/reset-password.php?token='.$token;send_reset_email($email,$link);}flash('success','If that email exists, a reset link was sent.');redirect('/forgot-password.php');}include __DIR__.'/includes/header.php';?><section class="section"><h1>Forgot Password</h1><form class="card form" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Email<input name="email" type="email"></label><button>Send</button></form></section><?php include __DIR__.'/includes/footer.php'; ?>